BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?useCase ?name WHERE {
  ?pkg vocab:NamedElement_name "TMT-APS Use Cases" .
  ?pkg vocab:Element_ownedElement+ ?useCase .
  ?useCase rdf:type vocab:usecase .
  OPTIONAL { ?useCase vocab:NamedElement_name ?name }
}
LIMIT 50

